let promotedValueText = "null";
let previousGlobalValueText = "There is no existing global value.";

const data = page.variables.allConfigValues?.[0];
const valueType = queries.fetchConfigDetails.data["Value Type"]
  ?.slice(5)
  ?.toLowerCase();

function getFormattedValue(item) {
  if (!item) return null;

  let currentValue =
    item.value === "float_value_v2"
      ? item[item.value]
      : item.value === "float_array_value_v2"
      ? item[item.value][`${item.value.split("_array_value")[0]}_values_v2`]
      : item.value.includes("array")
      ? item[item.value][`${item.value.split("_array_value")[0]}_values`]
      : item[item.value];

  if (valueType?.includes("array")) return JSON.stringify(currentValue);
  if (valueType === "int" || valueType === "float") return Number(currentValue);

  return currentValue;
}

/* -------- First value (deployment_value) -------- */
if (data?.deployment_value !== null) {
  promotedValueText = getFormattedValue(data.deployment_value);
}

/* -------- Second value (previous global value) -------- */
if (data?.value !== null) {
  const prevValue = getFormattedValue(data.value);
  previousGlobalValueText = `The previous global value "${prevValue}" will be replaced. Proceed with caution.`;
}

/* -------- Return both -------- */
return {
  promotedValueText,
  previousGlobalValueText
};
